const iterations = $.steps.fetchDetails.response.iterations || [];
const emails = [];
iterations.forEach((iter) => {
  const msg = (iter.getMsg && iter.getMsg.response) ? iter.getMsg.response : {};
  const headers = (msg.payload && msg.payload.headers) || [];
  const subject = (headers.find(h => h.name === 'Subject') || {}).value || 'No Subject';
  const from = (headers.find(h => h.name === 'From') || {}).value || 'Unknown';
  const date = (headers.find(h => h.name === 'Date') || {}).value || '';
  const snippet = msg.snippet || '';
  emails.push({ id: msg.id || '', subject, from, date, snippet });
});
let emailsText = '';
emails.forEach((e, i) => {
  emailsText += (i+1) + '. Subject: ' + e.subject + '\n';
  emailsText += '   From: ' + e.from + '\n';
  emailsText += '   Date: ' + e.date + '\n';
  emailsText += '   Preview: ' + e.snippet.slice(0, 300) + '\n\n';
});
return { emails, emailsText, count: emails.length };

const prompt = `You are an email triage assistant. Categorize each of the following emails by urgency and type.

EMAILS:
${$.steps.compileEmails.output.emailsText}

For each email, assign:
- urgency: "urgent", "important", "normal", or "low"
- type: one of "action_required", "meeting", "newsletter", "notification", "personal", "promotion", "billing", "support", "other"
- brief_summary: 1-sentence summary of what the email is about
- recommended_action: what the user should do (reply, read later, archive, etc.)

Return ONLY valid JSON:
{
  "categorized_emails": [
    {
      "index": 1,
      "subject": "...",
      "from": "...",
      "urgency": "...",
      "type": "...",
      "brief_summary": "...",
      "recommended_action": "..."
    }
  ],
  "stats": {
    "total": 0,
    "urgent": 0,
    "important": 0,
    "normal": 0,
    "low": 0
  },
  "top_priority": "Which email should be dealt with first and why"
}`;
return { prompt };

let raw = $.steps.aiCategorize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { categorized_emails: [], stats: { total: 0 }, top_priority: raw.slice(0, 500) }; }

const ai = $.steps.parseAI.output || {};
const stats = ai.stats || {};
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Gmail Inbox Categorization' } });
const urgencyEmoji = { urgent: ':rotating_light:', important: ':warning:', normal: ':large_blue_circle:', low: ':white_circle:' };
const statsText = (urgencyEmoji.urgent + ' Urgent: *' + (stats.urgent || 0) + '* | ' + urgencyEmoji.important + ' Important: *' + (stats.important || 0) + '* | ' + urgencyEmoji.normal + ' Normal: *' + (stats.normal || 0) + '* | ' + urgencyEmoji.low + ' Low: *' + (stats.low || 0) + '*');
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: statsText } });
blocks.push({ type: 'divider' });
if (ai.top_priority) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:star: Top Priority*\n' + ai.top_priority } });
  blocks.push({ type: 'divider' });
}
const grouped = { urgent: [], important: [], normal: [], low: [] };
(ai.categorized_emails || []).forEach(e => {
  const key = e.urgency || 'normal';
  if (grouped[key]) grouped[key].push(e);
  else grouped.normal.push(e);
});
['urgent', 'important', 'normal', 'low'].forEach(level => {
  if (grouped[level].length === 0) return;
  const emoji = urgencyEmoji[level] || '';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: emoji + ' *' + level.charAt(0).toUpperCase() + level.slice(1) + ' (' + grouped[level].length + ')*' } });
  grouped[level].forEach(e => {
    let itemText = '*' + (e.subject || 'No Subject') + '*\n';
    itemText += '_From: ' + (e.from || 'Unknown') + '_ | Type: `' + (e.type || 'other') + '`\n';
    itemText += e.brief_summary + '\n';
    itemText += ':point_right: ' + (e.recommended_action || 'Review');
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: itemText.slice(0, 1900) } });
  });
  blocks.push({ type: 'divider' });
});
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Categorized ' + (stats.total || $.steps.compileEmails.output.count) + ' emails from Gmail inbox' }] });
return { blocks, fallback: 'Gmail Categorization: ' + (stats.urgent || 0) + ' urgent, ' + (stats.important || 0) + ' important' };
